    `.trim(),methodologyBlocks:[{title:"Dataset",text:"A structured dataset of artifacts forms the foundation of the exhibition, allowing the objects to be organized, described, and explored beyond static display."},{title:"Clustering & Comparison",text:"Artifacts are grouped through clustering and visual comparison, revealing relationships in form, iconography, and function across the archive."},{title:"AI-assisted Reconstruction",text:"Selected artifacts are presented through original scans, enhanced images, and non-generative bronze reconstructions. The process preserves structural detail while improving visual legibility."},{title:"Narrative Interpretation",text:"Audio narratives, historical sources, and contextual framing extend the archive into an exhibition experience, connecting the objects to violence, displacement, survival, and memory."}],structure:`
